function initiateModifyTimelockInterval(
  bytes4 functionSelector, uint256 newTimelockInterval, uint256 extraTime
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Ensure a timelock interval over eight weeks is not set on this function.
  if (functionSelector == this.modifyTimelockInterval.selector) {
    require(
      newTimelockInterval <= 8 weeks,
      "Timelock interval of modifyTimelockInterval cannot exceed eight weeks."
    );
  }

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.modifyTimelockInterval.selector,
    abi.encode(functionSelector, newTimelockInterval),
    extraTime
  );
}

function getTimelock(
  bytes4 functionSelector, bytes memory arguments
) public view returns (
  bool exists,
  bool completed,
  bool expired,
  uint256 completionTime,
  uint256 expirationTime
) {
  // Get timelock ID using the supplied function arguments.
  bytes32 timelockID = keccak256(abi.encodePacked(arguments));

  // Get information on the current timelock, if one exists.
  completionTime = uint256(_timelocks[functionSelector][timelockID].complete);
  exists = completionTime != 0;
  expirationTime = uint256(_timelocks[functionSelector][timelockID].expires);
  completed = exists && now > completionTime;
  expired = exists && now > expirationTime;
}

function parseRR(
    bytes memory data,
    uint256 idx,
    uint256 lastIdx
) internal view returns (address, bytes memory) {
    bytes memory txt = readTXT(data, idx, lastIdx);

    // Must start with the magic word
    if (txt.length < 5 || !txt.equals(0, "ENS1 ", 0, 5)) {
        return (address(0), "");
    }

    // Parse the name or address
    uint256 lastTxtIdx = txt.find(5, txt.length - 5, " ");
    if (lastTxtIdx > txt.length) {
        address dnsResolver = parseAndResolve(txt, 5, txt.length);
        return (dnsResolver, "");
    } else {
        address dnsResolver = parseAndResolve(txt, 5, lastTxtIdx);
        return (
            dnsResolver,
            txt.substring(lastTxtIdx + 1, txt.length - lastTxtIdx - 1)
        );
    }
}

function renewAll(
    string[] calldata names,
    uint256 duration,
    bytes32 referrer
) external payable override {
    ETHRegistrarController controller = getController();
    uint256 length = names.length;
    uint256 total;
    for (uint256 i = 0; i < length; ) {
        IPriceOracle.Price memory price = controller.rentPrice(
            names[i],
            duration
        );
        uint256 totalPrice = price.base + price.premium;
        controller.renew{value: totalPrice}(names[i], duration, referrer);
        unchecked {
            ++i;
            total += totalPrice;
        }
    }
    // Send any excess funds back
    payable(msg.sender).transfer(address(this).balance);
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata _executionCallData,
    bytes32,
    address,
    address
)
    public
    pure
    override
    onlySingleCallTypeMode(_mode)
    onlyDefaultExecutionMode(_mode)
{
    (address target_,,) = _executionCallData.decodeSingle();

    address[] memory allowedTargets_ = getTermsInfo(_terms);
    uint256 allowedTargetsLength_ = allowedTargets_.length;
    for (uint256 i = 0; i < allowedTargetsLength_; ++i) {
        if (target_ == allowedTargets_[i]) {
            return;
        }
    }
    revert("AllowedTargetsEnforcer:target-address-not-allowed");
}

function setReferralLink(uint256 tokenId, string calldata referralLink) public onlyRouter override {

    require(bytes(referralLink).length > 0, "Referral link can't be empty");

    bytes32 newReferral = keccak256(abi.encodePacked(referralLink));
    require(referralLinks[newReferral] == 0, "Referral link already used");

    delete referralLinks[keccak256(abi.encodePacked(referralStrings[tokenId]))];

    string memory oldReferralLink = referralStrings[tokenId];

    //Set referral link for NFT
    referralLinks[newReferral] = tokenId;
    referralStrings[tokenId] = referralLink;

    emit ReferralLinkChanged(tokenId, oldReferralLink, referralLink);
}

function _handleSellerPayout(
    uint256 profit,
    StoredAuction storage auction,
    address currency
) internal {
    address fundsRecipient = auction.seller;

    if (_hasFeature(auction.features, FEATURE_MASK_RECIPIENT_OR_EXPIRY)) {
        (, address _fundsRecipient) = _getExpiryAndFundsRecipient(auction);
        if (_fundsRecipient != address(0)) {
            fundsRecipient = _fundsRecipient;
        }
    }

    // Transfer the remaining profit to the funds recipient
    _handleOutgoingTransfer(fundsRecipient, profit, currency, 50000);
}

function swapPositions(uint32 index1, uint32 index2, bool inDebtArray) external {
    _isAuthorized();
    // Get the new positions that will be at each index.
    uint32 newPosition1;
    uint32 newPosition2;

    if (inDebtArray) {
        newPosition1 = debtPositions[index2];
        newPosition2 = debtPositions[index1];
        // Swap positions.
        (debtPositions[index1], debtPositions[index2]) = (newPosition1, newPosition2);
    } else {
        newPosition1 = creditPositions[index2];
        newPosition2 = creditPositions[index1];
        // Swap positions.
        (creditPositions[index1], creditPositions[index2]) = (newPosition1, newPosition2);
    }

    emit PositionSwapped(newPosition1, newPosition2, index1, index2);
}

function performUpkeep(bytes calldata performData) external {
  if (trickSimulation && tx.origin == address(0)) {
    return;
  }

  if (msg.sender != forwarder) {
    revert InvalidCaller(msg.sender, forwarder);
  }

  if (useMorePerformGas) {
    uint256 startGas = gasleft();
    while (startGas - gasleft() < performGasToBurn) {} // burn gas
  }

  if (initialTimestamp == 0) {
    initialTimestamp = block.timestamp;
  }
  lastTimestamp = block.timestamp;
  counter = counter + 1;
  dataCopy = performData;
  emit PerformingUpkeep(tx.origin, initialTimestamp, lastTimestamp, previousPerformBlock, counter);
  previousPerformBlock = lastTimestamp;
}

function executeMatchOrders(
    address pausableZoneAddress,
    SeaportInterface seaportAddress,
    Order[] calldata orders,
    Fulfillment[] calldata fulfillments
) external payable override returns (Execution[] memory executions) {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }

    // Create a zone object from the zone address.
    PausableZone zone = PausableZone(pausableZoneAddress);

    // Call executeMatchOrders on the given zone and return the sequence
    // of transfers performed as part of matching the given orders.
    executions = zone.executeMatchOrders{ value: msg.value }(
        seaportAddress,
        orders,
        fulfillments
    );
}

function releaseFucusForTask(
    address operator,
    uint256 modelId,
    uint256 fucusToRelease
) external {
    // Only task manager should be able to release FUCUs
    if (msg.sender != address(inferenceTaskManager)) {
        revert OnlyTaskManager();
    }

    uint256 currentAllocated = operatorAllocatedFucus[operator][modelId];
    require(currentAllocated >= fucusToRelease, "Attempting to release more than allocated");
    operatorAllocatedFucus[operator][modelId] = currentAllocated - fucusToRelease;

    emit FucusReleased(operator, modelId, fucusToRelease);
}

