function _verifyRecover(
  address account, bytes32 digest, bytes memory signature
) private pure {
  // Ensure the signature length is correct.
  require(
    signature.length == 65,
    "Must supply a single 65-byte signature when owner is not a contract."
  );

  // Divide the signature in r, s and v variables.
  bytes32 r;
  bytes32 s;
  uint8 v;
  assembly {
    r := mload(add(signature, 0x20))
    s := mload(add(signature, 0x40))
    v := byte(0, mload(add(signature, 0x60)))
  }

  require(
    uint256(s) <= _MAX_UNMALLEABLE_S,
    "Signature `s` value cannot be potentially malleable."
  );

  require(v == 27 || v == 28, "Signature `v` value not permitted.");

  require(account == ecrecover(digest, v, r, s), "Invalid signature.");
}

function buildDomainSeparator() public returns (bytes32){
    string memory connect = "_";
    string memory suffix = "GSP";
    // name of the shares is the combination of suffix, connect and string of the GSP
    string memory name = string(abi.encodePacked(suffix, connect, addressToShortString(address(this))));

    DOMAIN_SEPARATOR = keccak256(
        abi.encode(
            // keccak256('EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)'),
            0x8b73c3c69bb8fe3d512ecc4cf759cc79239f7b179b0ffacaa9a75d522b39400f,
            keccak256(bytes(name)),
            keccak256(bytes("1")),
            block.chainid,
            address(this)
        )
    );
    return DOMAIN_SEPARATOR;
}

